 85→  display: block;
 86→  font-size: 11px;
 87→  color: var(--text-dim);
 88→  text-decoration: none;
 89→  padding: 4px 8px;
 90→  border-radius: 5px;
 91→  border-left: 2px solid transparent;
 92→  transition: all 0.15s;
 93→  line-height: 1.4;
 94→  margin-bottom: 1px;
 95→}
 96→.toc a:hover { color: var(--text); background: var(--surface2); }
 97→.toc a.active { color: var(--text); border-left-color: var(--accent); }
 98→```
 99→
100→Replace `var(--accent)` with your page's primary accent color variable (e.g., `var(--orange)`, `var(--blue)`).
101→
102→### TOC — Mobile (sticky horizontal bar)
103→
104→```css
105→@media (max-width: 1000px) {
106→  .wrap { grid-template-columns: 1fr; padding-top: 0; }
107→  body { padding-top: 0; }
108→
109→  .toc {
110→    position: sticky;
111→    top: 0;
112→    z-index: 200;
113→    max-height: none;
114→    display: flex;
115→    gap: 4px;
116→    align-items: center;
117→    overflow-x: auto;
118→    -webkit-overflow-scrolling: touch;
119→    background: var(--bg);
120→    border-bottom: 1px solid var(--border);
121→    padding: 10px 0;
122→    margin: 0 -40px;
123→    padding-left: 40px;
124→    padding-right: 40px;
125→    grid-row: auto;
126→  }
127→  .toc::-webkit-scrollbar { display: none; }
128→  .toc-title { display: none; }
129→
130→  .toc a {
131→    white-space: nowrap;
132→    flex-shrink: 0;
133→    border-left: none;
134→    border-bottom: 2px solid transparent;
135→    border-radius: 4px 4px 0 0;
136→    padding: 6px 10px;
137→    font-size: 10px;
138→  }
139→  .toc a.active {
140→    border-left: none;
141→    border-bottom-color: var(--accent);
142→    background: var(--surface);
143→  }
144→
145→  .main { padding-top: 20px; }
146→
147→  /* Offset scroll target so headings clear the sticky bar */
148→  .sec-head { scroll-margin-top: 52px; }
149→}
150→```
151→
152→Adjust `margin: 0 -40px` and `padding-left/right: 40px` to match your `body` padding so the bar bleeds edge-to-edge.
153→
154→## JavaScript — Scroll Spy
155→
156→Place before `</body>`, after any Mermaid init:
157→
158→```html
159→<script>
160→(function() {
161→  const toc = document.getElementById('toc');
162→  const links = toc.querySelectorAll('a');
163→  const sections = [];
164→
165→  links.forEach(link => {
166→    const id = link.getAttribute('href').slice(1);
167→    const el = document.getElementById(id);
168→    if (el) sections.push({ id, el, link });
169→  });
170→
171→  const observer = new IntersectionObserver(entries => {
172→    entries.forEach(entry => {
173→      if (entry.isIntersecting) {
174→        links.forEach(l => l.classList.remove('active'));
175→        const match = sections.find(s => s.el === entry.target);
176→        if (match) {
177→          match.link.classList.add('active');
178→          // On mobile, auto-scroll the active tab into view
179→          if (window.innerWidth <= 1000) {
180→            match.link.scrollIntoView({
181→              behavior: 'smooth', block: 'nearest', inline: 'center'
182→            });
183→          }
184→        }
185→      }
186→    });
187→  }, { rootMargin: '-10% 0px -80% 0px' });
188→
189→  sections.forEach(s => observer.observe(s.el));
190→
191→  links.forEach(link => {
192→    link.addEventListener('click', e => {
193→      e.preventDefault();
194→      const id = link.getAttribute('href').slice(1);
195→      const el = document.getElementById(id);
196→      if (el) {
197→        el.scrollIntoView({ behavior: 'smooth', block: 'start' });
198→        history.replaceState(null, '', '#' + id);
199→      }
200→    });
201→  });
202→})();
203→</script>
204→```
205→
206→## Adaptation Notes
207→
208→- The `.toc-title` text, link labels, accent color, and section IDs change per page. Everything else is copy-paste.
209→- For pages with fewer than 4 sections, skip the TOC entirely — it adds clutter without value.
210→- The `grid-template-columns: 170px 1fr` width works for most TOCs. If section names are longer, go up to `200px`.
211→- The `rootMargin: '-10% 0px -80% 0px'` means a section is "active" when its heading enters the top 10-20% of the viewport. This works well with sticky headers.
212→- On mobile, the horizontal bar uses `overflow-x: auto` with hidden scrollbar. The active tab auto-scrolls into the center of the bar as the user scrolls the page.
213→

