341→<script type="module">
342→  import mermaid from 'https://cdn.jsdelivr.net/npm/mermaid@11/dist/mermaid.esm.min.mjs';
343→  import elkLayouts from 'https://cdn.jsdelivr.net/npm/@mermaid-js/layout-elk/dist/mermaid-layout-elk.esm.min.mjs';
344→
345→  const isDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
346→
347→  mermaid.registerLayoutLoaders(elkLayouts);
348→  mermaid.initialize({
349→    startOnLoad: true,
350→    theme: 'base',
351→    look: 'classic',
352→    layout: 'elk',
353→    themeVariables: {
354→      primaryColor: isDark ? '#115e59' : '#ccfbf1',
355→      primaryBorderColor: isDark ? '#2dd4bf' : '#0d9488',
356→      primaryTextColor: isDark ? '#ccfbf1' : '#134e4a',
357→      secondaryColor: isDark ? '#0c4a6e' : '#e0f2fe',
358→      secondaryBorderColor: isDark ? '#38bdf8' : '#0369a1',
359→      secondaryTextColor: isDark ? '#ccfbf1' : '#134e4a',
360→      tertiaryColor: isDark ? '#2e2618' : '#fffbeb',
361→      tertiaryBorderColor: isDark ? '#fbbf24' : '#d97706',
362→      tertiaryTextColor: isDark ? '#ccfbf1' : '#134e4a',
363→      lineColor: isDark ? '#5eead4' : '#5f8a85',
364→      fontSize: '16px',
365→      fontFamily: "'Bricolage Grotesque', system-ui, sans-serif",
366→      noteBkgColor: isDark ? '#115e59' : '#fefce8',
367→      noteTextColor: isDark ? '#ccfbf1' : '#134e4a',
368→      noteBorderColor: isDark ? '#fbbf24' : '#d97706',
369→    }
370→  });
371→</script>
372→<script>
373→  function updateZoomState(wrap) {
374→    var target = wrap.querySelector('.mermaid');
375→    var zoom = parseFloat(target.dataset.zoom || '1');
376→    wrap.classList.toggle('is-zoomed', zoom > 1);
377→  }
378→
379→  function zoomDiagram(btn, factor) {
380→    var wrap = btn.closest('.mermaid-wrap');
381→    var target = wrap.querySelector('.mermaid');
382→    var current = parseFloat(target.dataset.zoom || '1');
383→    var next = Math.min(Math.max(current * factor, 0.3), 5);
384→    target.dataset.zoom = next;
385→    target.style.transform = 'scale(' + next + ')';
386→    updateZoomState(wrap);
387→  }
388→
389→  function resetZoom(btn) {
390→    var wrap = btn.closest('.mermaid-wrap');
391→    var target = wrap.querySelector('.mermaid');
392→    target.dataset.zoom = '1';
393→    target.style.transform = 'scale(1)';
394→    updateZoomState(wrap);
395→  }
396→
397→  document.querySelectorAll('.mermaid-wrap').forEach(function(wrap) {
398→    // Scroll-to-zoom (Ctrl/Cmd + wheel)
399→    wrap.addEventListener('wheel', function(e) {
400→      if (!e.ctrlKey && !e.metaKey) return;
401→      e.preventDefault();
402→      var target = wrap.querySelector('.mermaid');
403→      var current = parseFloat(target.dataset.zoom || '1');
404→      var factor = e.deltaY < 0 ? 1.1 : 0.9;
405→      var next = Math.min(Math.max(current * factor, 0.3), 5);
406→      target.dataset.zoom = next;
407→      target.style.transform = 'scale(' + next + ')';
408→      updateZoomState(wrap);
409→    }, { passive: false });
410→
411→    // Drag-to-pan
412→    var startX, startY, scrollL, scrollT;
413→    wrap.addEventListener('mousedown', function(e) {
414→      if (e.target.closest('.zoom-controls')) return;
415→      var target = wrap.querySelector('.mermaid');
416→      if (parseFloat(target.dataset.zoom || '1') <= 1) return;
417→      wrap.classList.add('is-panning');
418→      startX = e.clientX;
419→      startY = e.clientY;
420→      scrollL = wrap.scrollLeft;
421→      scrollT = wrap.scrollTop;
422→    });
423→    window.addEventListener('mousemove', function(e) {
424→      if (!wrap.classList.contains('is-panning')) return;
425→      wrap.scrollLeft = scrollL - (e.clientX - startX);
426→      wrap.scrollTop = scrollT - (e.clientY - startY);
427→    });
428→    window.addEventListener('mouseup', function() {
429→      wrap.classList.remove('is-panning');
430→    });
431→  });
432→</script>
433→
434→</body>
435→</html>
