862→  // SlideEngine
863→  function SlideEngine(){
864→    this.deck=document.querySelector('.deck');
865→    this.slides=[].slice.call(document.querySelectorAll('.slide'));
866→    this.current=0;
867→    this.total=this.slides.length;
868→    this.buildChrome();
869→    this.bindEvents();
870→    this.observe();
871→    this.update();
872→  }
873→  SlideEngine.prototype.buildChrome=function(){
874→    var bar=document.createElement('div');bar.className='deck-progress';document.body.appendChild(bar);this.bar=bar;
875→    var dots=document.createElement('div');dots.className='deck-dots';var self=this;
876→    this.slides.forEach(function(_,i){var d=document.createElement('button');d.className='deck-dot';d.title='Slide '+(i+1);d.onclick=function(){self.goTo(i);};dots.appendChild(d);});
877→    document.body.appendChild(dots);this.dots=[].slice.call(dots.children);
878→    var ctr=document.createElement('div');ctr.className='deck-counter';document.body.appendChild(ctr);this.counter=ctr;
879→    var hints=document.createElement('div');hints.className='deck-hints';hints.textContent='\u2190 \u2192 or scroll to navigate';document.body.appendChild(hints);this.hints=hints;
880→    this.hintTimer=setTimeout(function(){hints.classList.add('faded');},4000);
881→  };
882→  SlideEngine.prototype.bindEvents=function(){
883→    var self=this;
884→    document.addEventListener('keydown',function(e){
885→      if(e.target.closest('.mermaid-wrap,.table-scroll,.code-scroll,input,textarea,[contenteditable]'))return;
886→      if(['ArrowDown','ArrowRight',' ','PageDown'].indexOf(e.key)>-1){e.preventDefault();self.next();}
887→      else if(['ArrowUp','ArrowLeft','PageUp'].indexOf(e.key)>-1){e.preventDefault();self.prev();}
888→      else if(e.key==='Home'){e.preventDefault();self.goTo(0);}
889→      else if(e.key==='End'){e.preventDefault();self.goTo(self.total-1);}
890→      self.fadeHints();
891→    });
892→    var tY;
893→    this.deck.addEventListener('touchstart',function(e){tY=e.touches[0].clientY;},{passive:true});
894→    this.deck.addEventListener('touchend',function(e){var dy=tY-e.changedTouches[0].clientY;if(Math.abs(dy)>50){dy>0?self.next():self.prev();}});
895→  };
896→  SlideEngine.prototype.observe=function(){
897→    var self=this;
898→    var obs=new IntersectionObserver(function(entries){entries.forEach(function(entry){if(entry.isIntersecting){entry.target.classList.add('visible');self.current=self.slides.indexOf(entry.target);self.update();}});},{threshold:0.5});
899→    this.slides.forEach(function(s){obs.observe(s);});
900→  };
901→  SlideEngine.prototype.goTo=function(i){this.slides[Math.max(0,Math.min(i,this.total-1))].scrollIntoView({behavior:'smooth'});};
902→  SlideEngine.prototype.next=function(){if(this.current<this.total-1)this.goTo(this.current+1);};
903→  SlideEngine.prototype.prev=function(){if(this.current>0)this.goTo(this.current-1);};
904→  SlideEngine.prototype.update=function(){
905→    this.bar.style.width=((this.current+1)/this.total*100)+'%';
906→    var c=this.current;this.dots.forEach(function(d,i){d.classList.toggle('active',i===c);});
907→    this.counter.textContent=(this.current+1)+' / '+this.total;
908→  };
909→  SlideEngine.prototype.fadeHints=function(){clearTimeout(this.hintTimer);this.hints.classList.add('faded');};
910→</script>
